const input = $input.first().json;
const workflowName = String(input.workflowName || 'Hello from NodeBot');
const message = String(input.message || 'Hello from NodeBot!');
const safeName = workflowName.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
const safeMessage = message.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
const slug = workflowName.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '') || 'hello-nodebot';

const sdkCode = `import { workflow, node, trigger } from "@n8n/workflow-sdk";

const startTrigger = trigger({
  type: "n8n-nodes-base.manualTrigger",
  version: 1,
  config: { name: "When clicking Execute workflow" },
});

const setHello = node({
  type: "n8n-nodes-base.set",
  version: 3.4,
  config: {
    name: "Set Hello",
    parameters: {
      mode: "manual",
      assignments: {
        assignments: [
          { id: "hello", name: "message", value: "${safeMessage}", type: "string" },
        ],
      },
    },
  },
});

export default workflow("${slug}", "${safeName}")
  .add(startTrigger)
  .to(setHello);`;

return [{
  json: {
    workflowName,
    message,
    sdkCode,
    validateRpc: {
      jsonrpc: '2.0',
      id: 1,
      method: 'tools/call',
      params: { name: 'validate_workflow', arguments: { code: sdkCode } },
    },
    createRpc: {
      jsonrpc: '2.0',
      id: 2,
      method: 'tools/call',
      params: {
        name: 'create_workflow_from_code',
        arguments: {
          code: sdkCode,
          name: workflowName,
          description: `Manual trigger + Set node returning: ${message}`,
        },
      },
    },
  },
}];

function parseMcpSse(raw) {
  const text = typeof raw === 'string' ? raw : String(raw ?? '');
  const dataLine = text.split(/\r?\n/).find((line) => line.startsWith('data: '));
  if (!dataLine) {
    throw new Error('Invalid MCP validate response: ' + text.slice(0, 500));
  }
  const payload = JSON.parse(dataLine.slice(6));
  if (payload.error) {
    throw new Error(payload.error.message || JSON.stringify(payload.error));
  }
  const contentText = payload.result?.content?.[0]?.text;
  if (contentText) {
    return JSON.parse(contentText);
  }
  return payload.result?.structuredContent || {};
}

const http = $input.first().json;
const raw = http.body ?? http.data ?? '';
const validation = parseMcpSse(raw);
if (!validation.valid) {
  throw new Error('Workflow validation failed: ' + JSON.stringify(validation));
}

const built = $('Build SDK Payload').first().json;
return [{ json: { ...built, validation } }];

