const http = $input.first().json;
const created = parseMcpSse(http.body ?? http.data ?? '');
return [{
  json: {
    success: true,
    workflowId: created.workflowId,
    name: created.name,
    url: created.url,
    nodeCount: created.nodeCount,
    response: `Created workflow "${created.name}" (${created.nodeCount} nodes). Open ${created.url} in n8n to test it.`,
  },
}];
